    let mut v_type = CoreValue::Null;
    let mut v_url = CoreValue::Null;
    v_type = core_get(&v_part, &CoreValue::from("type"), CoreValue::Null);
    v_is_text = core_eq(&[v_type.clone(), CoreValue::from("text")])?;
