    let mut v_is_tool_calls = CoreValue::Null;
    let mut v_none = CoreValue::Null;
    v_is_stop = core_eq(&[v_value.clone(), CoreValue::from("stop")])?;
    if core_truthy(&v_is_stop) {
        return Ok(CoreValue::from("stop"));
    }
