    let mut v_content = CoreValue::Null;
    let mut v_empty_candidates = CoreValue::Null;
    let mut v_empty_parts = CoreValue::Null;
    let mut v_has_text = CoreValue::Null;
    let mut v_out = CoreValue::Null;
